mapper.update:
update weekk set update_time = now()

        , name = #{name}


        , open = #{open}


        , high = #{high}


        , low = #{low}


        , trade = #{trade}


        , last_trade = #{lastTrade}


        , percent = #{percent}


        , volume = #{volume}


        , amount = #{amount}


        , ma5 = #{ma5}


        , ma10 = #{ma10}


        , ma20 = #{ma20}


        , ma30 = #{ma30}


        , ma60 = #{ma60}


        , ma120 = #{ma120}


        , dea = #{dea}


         , dif = #{dif}


        , macd = #{macd}


        , cross_params = #{crossParams}


        , source_type = #{sourceType}

      where code = #{code} and day = #{day}

mapper.select:
select w.* from weekk w where
w.code = #{code} and w.day < #{fromDay}
order by w.day desc limit 1

   	select w.code, w.day, w.open, w.trade, w.last_trade, w.high, w.low, w.ma5, w.ma10, w.ma20, w.ma30, w.ma60, w.ma120, w.dea, w.dif, w.macd, w.source_type from weekk w


		  		and w.code = #{code}



				and	(select count(*) from weekk where code=w.code and day > w.day) < #{nweeks}
